// Detect if binary data (uploaded file) is present and pass it through
const item = $input.first();
const hasBinary = item.binary && Object.keys(item.binary).length > 0;
const output = { json: { ...item.json, hasImage: hasBinary } };
if (hasBinary) {
  output.binary = item.binary;
}
return [output];

// Format the API response as a readable chat message
const data = $input.first().json;

const emoji = data.emoji || '🔍';
const label = data.label || data.verdict;
const confidence = Math.round((data.confidence || 0) * 100);
const explanation = data.explanation || 'No explanation available.';
const tip = data.educational_tip || '';
const sources = data.sources || [];
const evidence = data.evidence_summary || {};
const responseTime = data.response_time_seconds || 0;
const imageAnalysis = data.image_analysis || null;

// Build the formatted message
let message = `${emoji} **${label}** (${confidence}% confidence)\n\n`;
message += `${explanation}\n\n`;

// Image analysis section (if present)
if (imageAnalysis) {
  message += `🖼️ **Image Analysis:**\n`;
  message += `${imageAnalysis.description}\n`;
  message += `Authenticity: ${imageAnalysis.authenticity_assessment}\n`;
  const aiSignals = imageAnalysis.ai_generation_signals || [];
  const manipSignals = imageAnalysis.manipulation_signals || [];
  if (aiSignals.length > 0) {
    message += `\n🤖 **AI Generation Signals:**\n`;
    for (const signal of aiSignals) {
      message += `• ${signal}\n`;
    }
  }
  if (manipSignals.length > 0) {
    message += `\n🖌️ **Manipulation Signals:**\n`;
    for (const signal of manipSignals) {
      message += `• ${signal}\n`;
    }
  }
  message += `\n`;
}

// Sources section
if (sources.length > 0) {
  message += `📋 **Sources:**\n`;
  for (const source of sources) {
    message += `• **${source.name}** — ${source.snippet}`;
    if (source.url) {
      message += ` ([link](${source.url}))`;
    }
    message += `\n`;
  }
  message += `\n`;
}

// Educational tip
if (tip) {
  message += `💡 **Tip:** ${tip}\n\n`;
}

// Evidence summary
message += `---\n`;
message += `_Checked ${evidence.knowledge_base_matches || 0} known patterns, `;
message += `${evidence.web_search_results || 0} web sources, `;
message += `${evidence.published_fact_checks || 0} published fact-checks`;
if (evidence.image_analyzed) {
  message += `, plus image analysis`;
}
message += ` in ${responseTime}s_`;

return [{ json: { output: message } }];
